class Solution:
    def minimumDeletions(self, word, k):
        from collections import Counter
        freq = sorted(Counter(word).values())
        best = float('inf')
        n = len(freq)
        for i in range(n):
            floor_val = freq[i]
            deletions = 0
            for j in range(n):
                if freq[j] < floor_val:
                    deletions += freq[j]
                elif freq[j] > floor_val + k:
                    deletions += freq[j] - (floor_val + k)
            best = min(best, deletions)
        # also try deleting everything (0 deletions if empty is valid) - but 0-floor also handled
        # also try floor=0: delete all chars below some threshold
        return best

