var minimumDeletions = function(word, k) {
    const freq = {};
    for (const c of word) freq[c] = (freq[c] || 0) + 1;
    const freqs = Object.values(freq).sort((a, b) => a - b);
    const n = freqs.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i+1] = prefix[i] + freqs[i];
    let best = Infinity;
    for (let i = 0; i < n; i++) {
        const floorVal = freqs[i];
        let deletions = prefix[i];
        const ceiling = floorVal + k;
        for (let j = i; j < n; j++) {
            if (freqs[j] > ceiling) deletions += freqs[j] - ceiling;
        }
        if (deletions < best) best = deletions;
    }
    return best;
};
